// build.gradle.kts

plugins {
    java                          // Плагин для компиляции Java
    application                   // Плагин для запуска приложения
}

repositories {
    mavenCentral()                // Где искать зависимости
}

dependencies {
    implementation("com.google.guava:guava:33.0.0-jre") // Основная зависимость
    testImplementation("org.junit.jupiter:junit-jupiter:5.10.2") // Тестовая
}

application {
    mainClass.set("com.example.App") // Главный класс (ваш Java-класс с main)
}

tasks.test {
    useJUnitPlatform()            // Обязательно для JUnit 5
}

// build.gradle.kts

repositories {
    mavenCentral()    // Главный публичный репозиторий
    google()          // Для Android-библиотек
    mavenLocal()      // Локальный кэш ~/.m2/repository

    // Кастомный репозиторий
    maven {
        url = uri("https://repo.mycompany.com/maven")
        credentials {
            username = project.findProperty("repoUser") as String? ?: ""
            password = project.findProperty("repoPass") as String? ?: ""
        }
    }
}

dependencies {
    testImplementation("org.junit.jupiter:junit-jupiter:5.10.2")
}

tasks.test {
    useJUnitPlatform()  // Обязательно для JUnit 5!
}
